for (const k of Object.keys(seen)) { if (now - seen[k] > 90*24*3600*1000) delete seen[k]; }
const out = [];
const allowedPrivacy = ['anybody','unlisted'];
for (const it of items) {
  const videos = (it.json && it.json.data) || [];
  for (const v of videos) {
    if (!v || !v.uri) continue;
    const priv = (v.privacy && v.privacy.view) || 'nobody';
    if (!allowedPrivacy.includes(priv)) continue;
    if (seen[v.uri]) continue;
    seen[v.uri] = now;
    const videoId = String(v.uri).replace('/videos/','').trim();
    out.push({ json: { video_id: videoId, video_uri: v.uri, name: v.name || '', description: v.description || '', created_time: v.created_time || '', link: v.link || '', privacy_view: priv, duration: v.duration || 0 } });
