return out;

const items = $input.all();
const metaAll = $('Vimeo: Preserve Metadata').all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const raw = items[i].json && (items[i].json.data || items[i].json.body || '');
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const lines = text.split(/\r?\n/);
  const plain = [];
  for (const line of lines) {
    if (!line) continue;
    if (/^WEBVTT/i.test(line)) continue;
    if (/^NOTE/i.test(line)) continue;
    if (/^\d+$/.test(line.trim())) continue;
    if (line.includes('-->')) continue;
    if (/^(Kind|Language|STYLE|Region):/i.test(line)) continue;
    plain.push(line.replace(/<[^>]+>/g,'').trim());
  }
  const transcript = plain.filter(Boolean).join(' ');
  const meta = metaAll[i] ? metaAll[i].json : (metaAll[0] ? metaAll[0].json : {});
  out.push({ json: { transcript, transcript_source: 'Vimeo', _episode_title: meta._episode_title || '', _episode_url: meta._episode_url || '', _episode_published: meta._episode_published || '', _podcast_name: meta._podcast_name || 'MMA Vimeo', _default_topics: meta._default_topics || [], _podcast_priority: meta._podcast_priority || 'high', source_type: 'vimeo' } });
}
return out;

