const out = [];
let skipped = 0;
for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const raw = (d.content && d.content[0] && d.content[0].text) ? d.content[0].text : "{}";
  const cleaned = raw.replace(/^\x60\x60\x60json\s*/i, "").replace(/\x60\x60\x60\s*$/, "").trim();
