const WINDOW_DAYS = 7;
const cutoff = Date.now() - WINDOW_DAYS * 24 * 60 * 60 * 1000;
const keywords = ["ai","artificial intelligence","claude","gpt","anthropic","openai","gemini","agent","llm","machine learning","marketing ai","martech","copilot","automation","mcp","model context protocol"];
function getTag(tag, block) {
  const re = new RegExp("<" + tag + "(?:\\s[^>]*)?>([\\s\\S]*?)<\\/" + tag + ">", "i");
  const m = block.match(re);
  if (!m) return "";
  let v = m[1];
  v = v.replace(/^\s*<!\[CDATA\[/, "").replace(/\]\]>\s*$/, "");
  return v.trim();
}
function getAttr(tag, name, block) {
