  const link = getTag("link", block);
  if (link && /^https?:\/\//i.test(link)) return link;
  const atomHref = getAttr("atom:link", "href", block);
  if (atomHref && /^https?:\/\//i.test(atomHref)) return atomHref;
  const gipm = /<guid[^>]*isPermaLink=\"true\"[^>]*>([\s\S]*?)<\/guid>/i.exec(block);
  if (gipm) {
    const v = gipm[1].replace(/^\s*<!\[CDATA\[/, "").replace(/\]\]>\s*$/, "").trim();
    if (/^https?:\/\//i.test(v)) return v;
  }
  const g = getTag("guid", block);
  if (g && /^https?:\/\//i.test(g)) return g;
  return "";
}
const out = [];
