    out.push({ json: {
      title,
      link: episodeUrl,
      isoDate: new Date(t).toISOString(),
      pubDate: pub,
      contentSnippet: descText,
      audio_url: enclosureUrl,
      podcast_name: feed.podcast_name,
      default_topics: feed.default_topics,
      podcast_priority: feed.podcast_priority
    }});
  }
}
return out;

